package main.rice.test;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * Represents a single test case: an ordered list of Python object arguments.
 */
public class TestCase {

    /** The arguments for this test case. */
    private final List<APyObj> args;

    /**
     * Constructs a TestCase with the given argument list.
     *
     * @param args the list of Python object arguments
     */
    public TestCase(List<APyObj> args) {
        this.args = new ArrayList<>(args);
    }

    /**
     * Returns the argument list for this test case.
     *
     * @return the argument list
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Two TestCases are equal iff their argument lists are equal
     * (element-by-element, in order).
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase)) {
            return false;
        }
        return this.args.equals(((TestCase) obj).args);
    }

    /**
     * Hash code consistent with equals.
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }

    /**
     * Returns a string representation of this test case.
     */
    @Override
    public String toString() {
        return this.args.toString();
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python list values.
 * The exDomain and ranDomain contain possible list lengths.
 * Elements are generated by the left child node.
 *
 * @param <InnerType> the type of each element in the list
 */
public class PyListNode<InnerType extends APyObj>
        extends AIterablePyNode<PyListObj<InnerType>> {

    private static final Random RAND = new Random();

    /**
     * Constructs a PyListNode with the given element-generating child node.
     *
     * @param leftChild the node used to generate list elements
     */
    public PyListNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    /**
     * Generates all exhaustive list values. For each length in exDomain,
     * produces all sequences (with repetition) of that length from the
     * child's exhaustive values.
     *
     * @return a set of all exhaustive PyListObj values
     */
    @Override
    @SuppressWarnings("unchecked")
    public Set<PyListObj<InnerType>> genExVals() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        List<InnerType> childVals = new ArrayList<>(child.genExVals());
        Set<PyListObj<InnerType>> result = new HashSet<>();
        for (int len : exDomain) {
            for (List<InnerType> seq : genSequences(childVals, len)) {
                result.add(new PyListObj<>(seq));
            }
        }
        return result;
    }

    /**
     * Generates a single random list by choosing a length uniformly from
     * ranDomain and filling it with random elements from the child node.
     *
     * @return a random PyListObj
     */
    @Override
    @SuppressWarnings("unchecked")
    public PyListObj<InnerType> genRandVal() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        int len = ranDomain.get(RAND.nextInt(ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(child.genRandVal());
        }
        return new PyListObj<>(elements);
    }

    /**
     * Recursively generates all sequences of the given length from vals,
     * allowing repetition (order matters).
     *
     * @param vals the pool of values to draw from
     * @param len  the target sequence length
     * @return all length-len sequences with repetition
     */
    private List<List<InnerType>> genSequences(List<InnerType> vals, int len) {
        List<List<InnerType>> result = new ArrayList<>();
        if (len == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        for (List<InnerType> sub : genSequences(vals, len - 1)) {
            for (InnerType val : vals) {
                List<InnerType> newSeq = new ArrayList<>(sub);
                newSeq.add(val);
                result.add(newSeq);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python string values.
 * The exDomain and ranDomain contain possible string lengths.
 * Characters are drawn from a fixed alphabet provided at construction time.
 */
public class PyStringNode extends APyNode<PyStringObj> {

    private static final Random RAND = new Random();

    /** The set of allowed characters as a list (for indexed access). */
    private final List<Character> chars;

    /**
     * Constructs a PyStringNode with the given character alphabet.
     *
     * @param chars a string whose characters form the allowed alphabet
     */
    public PyStringNode(String chars) {
        this.chars = new ArrayList<>();
        for (int i = 0; i < chars.length(); i++) {
            this.chars.add(chars.charAt(i));
        }
    }

    /**
     * Generates all exhaustive string values. For each length in exDomain,
     * produces all character sequences (with repetition) of that length
     * from the alphabet.
     *
     * @return a set of all exhaustive PyStringObj values
     */
    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();
        for (int len : exDomain) {
            for (List<Character> seq : genCharSequences(chars, len)) {
                List<PyCharObj> charObjs = new ArrayList<>();
                for (Character c : seq) {
                    charObjs.add(new PyCharObj(c));
                }
                result.add(new PyStringObj(charObjs));
            }
        }
        return result;
    }

    /**
     * Generates a single random string by choosing a length uniformly from
     * ranDomain and filling it with random characters from the alphabet.
     *
     * @return a random PyStringObj
     */
    @Override
    public PyStringObj genRandVal() {
        int len = ranDomain.get(RAND.nextInt(ranDomain.size()));
        List<PyCharObj> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(new PyCharObj(chars.get(RAND.nextInt(chars.size()))));
        }
        return new PyStringObj(elements);
    }

    /**
     * Recursively generates all character sequences of the given length
     * from the alphabet, allowing repetition.
     *
     * @param alphabet the pool of characters to draw from
     * @param len      the target sequence length
     * @return all length-len character sequences with repetition
     */
    private List<List<Character>> genCharSequences(List<Character> alphabet, int len) {
        List<List<Character>> result = new ArrayList<>();
        if (len == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        for (List<Character> sub : genCharSequences(alphabet, len - 1)) {
            for (Character c : alphabet) {
                List<Character> newSeq = new ArrayList<>(sub);
                newSeq.add(c);
                result.add(newSeq);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * Abstract base class for iterable Python node types (list, set, tuple, etc.).
 * Has a left child node that generates the elements of the iterable.
 *
 * @param <T> the type of Python object this node generates (e.g., PyListObj)
 */
public abstract class AIterablePyNode<T extends APyObj> extends APyNode<T> {

    /** The child node used to generate individual elements. */
    protected APyNode<?> leftChild;

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    public APyNode<?> getLeftChild() {
        return leftChild;
    }
}

