package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python dict values.
 * The exDomain and ranDomain contain possible dict sizes (number of key-value pairs).
 * Keys are generated by the left child node; values by the right child node.
 * Dict keys must be distinct.
 *
 * @param <KeyType> the type of each key
 * @param <ValType> the type of each value
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    private static final Random RAND = new Random();

    /** The node used to generate dict keys. */
    private final APyNode<KeyType> leftChild;

    /** The node used to generate dict values. */
    private final APyNode<ValType> rightChild;

    /**
     * Constructs a PyDictNode with the given key and value child nodes.
     *
     * @param leftChild  the node generating keys
     * @param rightChild the node generating values
     */
    public PyDictNode(APyNode<KeyType> leftChild, APyNode<ValType> rightChild) {
        this.leftChild = leftChild;
        this.rightChild = rightChild;
    }

    /**
     * Returns the left (key) child node.
     *
     * @return the key-generating child node
     */
    public APyNode<KeyType> getLeftChild() {
        return leftChild;
    }

    /**
     * Returns the right (value) child node.
     *
     * @return the value-generating child node
     */
    public APyNode<ValType> getRightChild() {
        return rightChild;
    }

    /**
     * Generates all exhaustive dict values. For each size in exDomain,
     * produces all dicts by choosing all combinations of that many distinct
     * keys and pairing each key-set with all combinations of values.
     *
     * @return a set of all exhaustive PyDictObj values
     */
    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        List<KeyType> keyVals = new ArrayList<>(leftChild.genExVals());
        List<ValType> valVals = new ArrayList<>(rightChild.genExVals());
        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
        for (int size : exDomain) {
            List<List<KeyType>> keySubsets = genCombinations(keyVals, size);
            for (List<KeyType> keys : keySubsets) {
                // Generate all value sequences for this key set
                for (List<ValType> vals : genSequences(valVals, size)) {
                    Map<KeyType, ValType> map = new LinkedHashMap<>();
                    for (int i = 0; i < keys.size(); i++) {
                        map.put(keys.get(i), vals.get(i));
                    }
                    result.add(new PyDictObj<>(map));
                }
            }
        }
        return result;
    }

    /**
     * Generates a single random dict by choosing a size uniformly from
     * ranDomain, then picking distinct random keys and random values.
     *
     * @return a random PyDictObj
     */
    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int size = ranDomain.get(RAND.nextInt(ranDomain.size()));
        Map<KeyType, ValType> map = new LinkedHashMap<>();
        while (map.size() < size) {
            KeyType key = leftChild.genRandVal();
            ValType val = rightChild.genRandVal();
            map.put(key, val);
        }
        return new PyDictObj<>(map);
    }

    /**
     * Generates all combinations (subsets) of the given size from vals,
     * without repetition. Returns them as ordered lists for index alignment
     * with value sequences.
     *
     * @param vals the pool of values
     * @param size the combination size
     * @return all size-element combinations as lists
     */
    private List<List<KeyType>> genCombinations(List<KeyType> vals, int size) {
        List<List<KeyType>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        if (size > vals.size()) {
            return result;
        }
        for (int i = 0; i <= vals.size() - size; i++) {
            KeyType elem = vals.get(i);
            List<KeyType> remaining = vals.subList(i + 1, vals.size());
            for (List<KeyType> sub : genCombinations(remaining, size - 1)) {
                List<KeyType> newList = new ArrayList<>();
                newList.add(elem);
                newList.addAll(sub);
                result.add(newList);
            }
        }
        return result;
    }

    /**
     * Recursively generates all sequences of the given length from vals,
     * allowing repetition (order matters).
     *
     * @param vals the pool of values
     * @param len  the target sequence length
     * @return all length-len sequences with repetition
     */
    private List<List<ValType>> genSequences(List<ValType> vals, int len) {
        List<List<ValType>> result = new ArrayList<>();
        if (len == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        for (List<ValType> sub : genSequences(vals, len - 1)) {
            for (ValType val : vals) {
                List<ValType> newSeq = new ArrayList<>(sub);
                newSeq.add(val);
                result.add(newSeq);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.*;

/**
 * A node that generates Python int values.
 * The exDomain and ranDomain contain the actual integer values (not lengths).
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private static final Random RAND = new Random();

    /**
     * Generates all exhaustive int values from the exDomain.
     *
     * @return a set of PyIntObj values, one per value in exDomain
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new LinkedHashSet<>();
        for (Integer val : exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    /**
     * Generates a single random PyIntObj chosen uniformly from ranDomain.
     *
     * @return a random PyIntObj
     */
    @Override
    public PyIntObj genRandVal() {
        return new PyIntObj(ranDomain.get(RAND.nextInt(ranDomain.size())));
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python set values.
 * The exDomain and ranDomain contain possible set sizes.
 * Elements are generated by the left child node.
 * Sets do not allow duplicate elements.
 *
 * @param <InnerType> the type of each element in the set
 */
public class PySetNode<InnerType extends APyObj>
        extends AIterablePyNode<PySetObj<InnerType>> {

    private static final Random RAND = new Random();

    /**
     * Constructs a PySetNode with the given element-generating child node.
     *
     * @param leftChild the node used to generate set elements
     */
    public PySetNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    /**
     * Generates all exhaustive set values. For each size in exDomain,
     * produces all subsets (combinations without repetition) of that size
     * from the child's exhaustive values.
     *
     * @return a set of all exhaustive PySetObj values
     */
    @Override
    @SuppressWarnings("unchecked")
    public Set<PySetObj<InnerType>> genExVals() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        List<InnerType> childVals = new ArrayList<>(child.genExVals());
        Set<PySetObj<InnerType>> result = new HashSet<>();
        for (int size : exDomain) {
            for (Set<InnerType> subset : genSubsets(childVals, size)) {
                result.add(new PySetObj<>(subset));
            }
        }
        return result;
    }

    /**
     * Generates a single random set by choosing a size uniformly from
     * ranDomain and filling it with distinct random elements from the child.
     *
     * @return a random PySetObj
     */
    @Override
    @SuppressWarnings("unchecked")
    public PySetObj<InnerType> genRandVal() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        int size = ranDomain.get(RAND.nextInt(ranDomain.size()));
        Set<InnerType> elements = new LinkedHashSet<>();
        while (elements.size() < size) {
            elements.add(child.genRandVal());
        }
        return new PySetObj<>(elements);
    }

    /**
     * Recursively generates all subsets of the given size from vals
     * (combinations without repetition, order does not matter).
     *
     * @param vals the pool of values to draw from
     * @param size the target subset size
     * @return all size-element subsets
     */
    private List<Set<InnerType>> genSubsets(List<InnerType> vals, int size) {
        List<Set<InnerType>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new LinkedHashSet<>());
            return result;
        }
        if (size > vals.size()) {
            return result;
        }
        for (int i = 0; i <= vals.size() - size; i++) {
            InnerType elem = vals.get(i);
            List<InnerType> remaining = vals.subList(i + 1, vals.size());
            for (Set<InnerType> sub : genSubsets(remaining, size - 1)) {
                Set<InnerType> newSet = new LinkedHashSet<>();
                newSet.add(elem);
                newSet.addAll(sub);
                result.add(newSet);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * Abstract base class for all Python node types. Each node represents
 * a domain of possible Python values and can generate exhaustive or
 * random samples from that domain.
 *
 * @param <T> the type of Python object this node generates
 */
public abstract class APyNode<T extends APyObj> {

    /** The exhaustive domain specification (e.g., list of values or lengths). */
    protected List<Integer> exDomain;

    /** The random domain specification (e.g., list of values or lengths). */
    protected List<Integer> ranDomain;

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = new ArrayList<>(exDomain);
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = new ArrayList<>(ranDomain);
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Generates all exhaustive values in this node's domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value from this node's random domain.
     *
     * @return a random value
     */
    public abstract T genRandVal();
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * Generates test cases (sets of argument tuples) from a list of argument
 * node specifications. Supports exhaustive generation (Cartesian product)
 * and random generation (unique random samples).
 */
public class BaseSetGenerator {

    /** The nodes, one per function argument. */
    private final List<APyNode<?>> nodes;

    /** The number of random test cases to include in the base set. */
    private final int numRand;

    /**
     * Constructs a BaseSetGenerator.
     *
     * @param nodes   one node per argument, defining its domain
     * @param numRand the number of random test cases to add beyond exhaustive ones
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = new ArrayList<>(nodes);
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases by taking the Cartesian product
     * of each argument node's exhaustive values.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        // Start with a single empty test case
        Set<TestCase> result = new HashSet<>();
        result.add(new TestCase(new ArrayList<>()));

        for (APyNode<?> node : nodes) {
            Set<TestCase> newResult = new HashSet<>();
            Set<?> nodeVals = node.genExVals();
            for (TestCase tc : result) {
                for (Object val : nodeVals) {
                    List<APyObj> newArgs = new ArrayList<>(tc.getArgs());
                    newArgs.add((APyObj) val);
                    newResult.add(new TestCase(newArgs));
                }
            }
            result = newResult;
        }
        return result;
    }

    /**
     * Generates numRand random test cases that are not already in the
     * provided set of existing test cases.
     *
     * @param existing the set of test cases to exclude
     * @return a list of unique random test cases not in existing
     */
    public List<TestCase> genRandTests(Set<TestCase> existing) {
        Set<TestCase> seen = new HashSet<>(existing);
        List<TestCase> result = new ArrayList<>();
        int count = 0;
        while (count < numRand) {
            TestCase tc = genOneRandTest();
            if (!seen.contains(tc)) {
                seen.add(tc);
                result.add(tc);
                count++;
            }
        }
        return result;
    }

    /**
     * Returns the combined base set: all exhaustive test cases followed by
     * numRand additional unique random test cases.
     *
     * @return the full base set as a list
     */
    public List<TestCase> genBaseSet() {
        Set<TestCase> exTests = genExTests();
        List<TestCase> result = new ArrayList<>(exTests);
        result.addAll(genRandTests(exTests));
        return result;
    }

    /**
     * Generates a single test case by calling genRandVal() on each node.
     *
     * @return a randomly generated test case
     */
    private TestCase genOneRandTest() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : nodes) {
            args.add(node.genRandVal());
        }
        return new TestCase(args);
    }
}

