+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import java.util.*;
+
+/**
+ * Abstract base class for all Python node types. Each node represents
+ * a domain of possible Python values and can generate exhaustive or
+ * random samples from that domain.
+ *
+ * @param <T> the type of Python object this node generates
+ */
+public abstract class APyNode<T extends APyObj> {
+
+    /** The exhaustive domain specification (e.g., list of values or lengths). */
+    protected List<Integer> exDomain;
+
+    /** The random domain specification (e.g., list of values or lengths). */
+    protected List<Integer> ranDomain;
+
+    /**
+     * Sets the exhaustive domain.
+     *
+     * @param exDomain the exhaustive domain
+     */
+    public void setExDomain(List<Integer> exDomain) {
+        this.exDomain = new ArrayList<>(exDomain);
+    }
+
+    /**
+     * Returns the exhaustive domain.
+     *
+     * @return the exhaustive domain
+     */
+    public List<Integer> getExDomain() {
+        return this.exDomain;
+    }
+
+    /**
+     * Sets the random domain.
+     *
+     * @param ranDomain the random domain
+     */
+    public void setRanDomain(List<Integer> ranDomain) {
+        this.ranDomain = new ArrayList<>(ranDomain);
+    }
+
+    /**
+     * Returns the random domain.
+     *
+     * @return the random domain
+     */
+    public List<Integer> getRanDomain() {
+        return this.ranDomain;
+    }
+
+    /**
+     * Generates all exhaustive values in this node's domain.
+     *
+     * @return a set of all exhaustive values
+     */
+    public abstract Set<T> genExVals();
+
+    /**
+     * Generates a single random value from this node's random domain.
+     *
+     * @return a random value
+     */
+    public abstract T genRandVal();
+}
diff --git a/skeleton_code/src/main/rice/node/PyDictNode.java b/skeleton_code/src/main/rice/node/PyDictNode.java
new file mode 100644
index 0000000..eeeacae
--- /dev/null
+++ b/skeleton_code/src/main/rice/node/PyDictNode.java
@@ -0,0 +1,155 @@
+package main.rice.node;
+
+import main.rice.obj.*;
+import java.util.*;
+
+/**
+ * A node that generates Python dict values.
+ * The exDomain and ranDomain contain possible dict sizes (number of key-value pairs).
+ * Keys are generated by the left child node; values by the right child node.
+ * Dict keys must be distinct.
+ *
+ * @param <KeyType> the type of each key
+ * @param <ValType> the type of each value
+ */
+public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
+        extends APyNode<PyDictObj<KeyType, ValType>> {
+
+    private static final Random RAND = new Random();
+
+    /** The node used to generate dict keys. */
+    private final APyNode<KeyType> leftChild;
+
+    /** The node used to generate dict values. */
+    private final APyNode<ValType> rightChild;
+
+    /**
+     * Constructs a PyDictNode with the given key and value child nodes.
+     *
+     * @param leftChild  the node generating keys
+     * @param rightChild the node generating values
+     */
+    public PyDictNode(APyNode<KeyType> leftChild, APyNode<ValType> rightChild) {
+        this.leftChild = leftChild;
+        this.rightChild = rightChild;
+    }
+
+    /**
+     * Returns the left (key) child node.
+     *
+     * @return the key-generating child node
+     */
+    public APyNode<KeyType> getLeftChild() {
+        return leftChild;
+    }
+
+    /**
+     * Returns the right (value) child node.
+     *
+     * @return the value-generating child node
+     */
+    public APyNode<ValType> getRightChild() {
+        return rightChild;
+    }
+
+    /**
+     * Generates all exhaustive dict values. For each size in exDomain,
+     * produces all dicts by choosing all combinations of that many distinct
+     * keys and pairing each key-set with all combinations of values.
+     *
+     * @return a set of all exhaustive PyDictObj values
+     */
+    @Override
+    public Set<PyDictObj<KeyType, ValType>> genExVals() {
+        List<KeyType> keyVals = new ArrayList<>(leftChild.genExVals());
+        List<ValType> valVals = new ArrayList<>(rightChild.genExVals());
+        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
+        for (int size : exDomain) {
+            List<List<KeyType>> keySubsets = genCombinations(keyVals, size);
+            for (List<KeyType> keys : keySubsets) {
+                // Generate all value sequences for this key set
+                for (List<ValType> vals : genSequences(valVals, size)) {
+                    Map<KeyType, ValType> map = new LinkedHashMap<>();
+                    for (int i = 0; i < keys.size(); i++) {
+                        map.put(keys.get(i), vals.get(i));
+                    }
+                    result.add(new PyDictObj<>(map));
+                }
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random dict by choosing a size uniformly from
+     * ranDomain, then picking distinct random keys and random values.
+     *
+     * @return a random PyDictObj
+     */
+    @Override
+    public PyDictObj<KeyType, ValType> genRandVal() {
+        int size = ranDomain.get(RAND.nextInt(ranDomain.size()));
+        Map<KeyType, ValType> map = new LinkedHashMap<>();
+        while (map.size() < size) {
+            KeyType key = leftChild.genRandVal();
+            ValType val = rightChild.genRandVal();
+            map.put(key, val);
+        }
+        return new PyDictObj<>(map);
+    }
+
+    /**
+     * Generates all combinations (subsets) of the given size from vals,
+     * without repetition. Returns them as ordered lists for index alignment
+     * with value sequences.
+     *
+     * @param vals the pool of values
+     * @param size the combination size
+     * @return all size-element combinations as lists
+     */
+    private List<List<KeyType>> genCombinations(List<KeyType> vals, int size) {
+        List<List<KeyType>> result = new ArrayList<>();
+        if (size == 0) {
+            result.add(new ArrayList<>());
+            return result;
+        }
+        if (size > vals.size()) {
+            return result;
+        }
+        for (int i = 0; i <= vals.size() - size; i++) {
+            KeyType elem = vals.get(i);
+            List<KeyType> remaining = vals.subList(i + 1, vals.size());
+            for (List<KeyType> sub : genCombinations(remaining, size - 1)) {
+                List<KeyType> newList = new ArrayList<>();
+                newList.add(elem);
+                newList.addAll(sub);
+                result.add(newList);
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Recursively generates all sequences of the given length from vals,
+     * allowing repetition (order matters).
+     *
+     * @param vals the pool of values
+     * @param len  the target sequence length
+     * @return all length-len sequences with repetition
+     */
+    private List<List<ValType>> genSequences(List<ValType> vals, int len) {
+        List<List<ValType>> result = new ArrayList<>();
+        if (len == 0) {
+            result.add(new ArrayList<>());
+            return result;
+        }
+        for (List<ValType> sub : genSequences(vals, len - 1)) {
+            for (ValType val : vals) {
+                List<ValType> newSeq = new ArrayList<>(sub);
+                newSeq.add(val);
+                result.add(newSeq);
+            }
+        }
+        return result;
+    }
+}
