+package main.rice.node;
+
+import main.rice.obj.*;
+import java.util.*;
+
+/**
+ * A node that generates Python string values.
+ * The exDomain and ranDomain contain possible string lengths.
+ * Characters are drawn from a fixed alphabet provided at construction time.
+ */
+public class PyStringNode extends APyNode<PyStringObj> {
+
+    private static final Random RAND = new Random();
+
+    /** The set of allowed characters as a list (for indexed access). */
+    private final List<Character> chars;
+
+    /**
+     * Constructs a PyStringNode with the given character alphabet.
+     *
+     * @param chars a string whose characters form the allowed alphabet
+     */
+    public PyStringNode(String chars) {
+        this.chars = new ArrayList<>();
+        for (int i = 0; i < chars.length(); i++) {
+            this.chars.add(chars.charAt(i));
+        }
+    }
+
+    /**
+     * Generates all exhaustive string values. For each length in exDomain,
+     * produces all character sequences (with repetition) of that length
+     * from the alphabet.
+     *
+     * @return a set of all exhaustive PyStringObj values
+     */
+    @Override
+    public Set<PyStringObj> genExVals() {
+        Set<PyStringObj> result = new HashSet<>();
+        for (int len : exDomain) {
+            for (List<Character> seq : genCharSequences(chars, len)) {
+                List<PyCharObj> charObjs = new ArrayList<>();
+                for (Character c : seq) {
+                    charObjs.add(new PyCharObj(c));
+                }
+                result.add(new PyStringObj(charObjs));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random string by choosing a length uniformly from
+     * ranDomain and filling it with random characters from the alphabet.
+     *
+     * @return a random PyStringObj
+     */
+    @Override
+    public PyStringObj genRandVal() {
+        int len = ranDomain.get(RAND.nextInt(ranDomain.size()));
+        List<PyCharObj> elements = new ArrayList<>();
+        for (int i = 0; i < len; i++) {
+            elements.add(new PyCharObj(chars.get(RAND.nextInt(chars.size()))));
+        }
+        return new PyStringObj(elements);
+    }
+
+    /**
+     * Recursively generates all character sequences of the given length
+     * from the alphabet, allowing repetition.
+     *
+     * @param alphabet the pool of characters to draw from
+     * @param len      the target sequence length
+     * @return all length-len character sequences with repetition
+     */
+    private List<List<Character>> genCharSequences(List<Character> alphabet, int len) {
+        List<List<Character>> result = new ArrayList<>();
+        if (len == 0) {
+            result.add(new ArrayList<>());
+            return result;
+        }
+        for (List<Character> sub : genCharSequences(alphabet, len - 1)) {
+            for (Character c : alphabet) {
+                List<Character> newSeq = new ArrayList<>(sub);
+                newSeq.add(c);
+                result.add(newSeq);
+            }
+        }
+        return result;
+    }
+}
